`).filter(Boolean).length>=2&&e.split(`
`).filter(Boolean).length<=6,ok:"✓ awk NR — line-range filtering.",xp:25}]},d4:{day:"Day 4",title:"Bash Scripting Fundamentals",intro:"Bash scripts automate everything. Variables, loops, conditionals — nail these.",type:"terminal",exercises:[{id:"d4e1",prompt:'Create a variable NAME="GK" and print it with echo',hint:'NAME="GK" && echo $NAME',check:e=>e.trim()==="GK",ok:"✓ Variables — no spaces around =.",xp:10},{id:"d4e2",prompt:"Print numbers 1 to 5 using a for loop",hint:"for i in {1..5}; do echo $i; done",check:e=>e.includes("1")&&e.includes("5")&&e.split(`
